// Full KillAura loop example:
public void onTick() {
  EntityLivingBase target = findTarget();
  if (target == null) return;
  mc.thePlayer.swingItem();
  // Send attack
  mc.thePlayer.sendQueue.addToSendQueue(new C02PacketUseEntity(target, C02PacketUseEntity.Action.ATTACK));
  // Also send criticals if on ground
  if (mc.thePlayer.onGround && doCriticals) sendCritPackets();
  // Autoblock after attack
  if (autoBlock) mc.thePlayer.sendQueue.addToSendQueue(
    new C07PacketPlayerDigging(C07PacketPlayerDigging.Action.RELEASE_USE_ITEM, BlockPos.ORIGIN, EnumFacing.DOWN));
}

// Lycoris 1.0 - Criticals.java
@EventTarget
public void onSend(EventSendPacket e) {
  if (e.getPacket() instanceof C02PacketUseEntity) {
    C02PacketUseEntity packet = (C02PacketUseEntity) e.getPacket();
    if (packet.getAction() == C02PacketUseEntity.Action.ATTACK
        && mc.thePlayer.isCollidedVertically && hurtTimeCheck()) {
      // Inject critical positions
      doCrits();
      // The attack packet goes through after criticals
    }
  }
}

private void doCrits() {
  double x = mc.thePlayer.posX, y = mc.thePlayer.posY, z = mc.thePlayer.posZ;
  mc.getNetHandler().addToSendQueue(new C04PacketPlayerPosition(x, y + 0.0625, z, false));
  mc.getNetHandler().addToSendQueue(new C04PacketPlayerPosition(x, y, z, false));
  // The attack C02 follows immediately
}

// Celestial Premium 6.0 - NoDamageFriends.java
@EventTarget
public void onSendPacket(EventSendPacket event) {
  if (event.getPacket() instanceof C02PacketUseEntity) {
    C02PacketUseEntity packet = (C02PacketUseEntity) event.getPacket();
    if (packet.getAction() == C02PacketUseEntity.Action.ATTACK) {
      Entity target = packet.getEntityFromWorld(mc.theWorld);
      if (target != null && Celestial.instance.friendManager.isFriend(target.getName())) {
        event.setCancelled(true);  // don"t attack friend
      }
    }
  }
}

